// Simple handler — called on every outside click
v-click-outside="onClickOutside"

// Full options object
v-click-outside="{
  handler: onClickOutside,
  closeConditional: (e) => isOpen.value,
  include: () => [extraEl]
}"

// Enabled — follows createOrigam({ contrast }) global config
v-contrast

// Per-element opt-out
v-contrast="false"

// Toggle a CSS class on hover
v-hover="{ class: 'is-hovered' }"

// Invoke a callback with the hover state (boolean)
v-hover.callback="onHoverChange"

// Stop pointer-event propagation on hover
v-hover.stop

// Simple handler
v-intersect="onIntersect"

// With IntersectionObserver options
v-intersect="{ handler: onIntersect, options: { threshold: 0.5 } }"

// Fire once on enter, then auto-disconnect
v-intersect.once="onEntered"

// Skip the initial call triggered on observer setup
v-intersect.quiet="onIntersect"

// Default — ripple from pointer position
v-ripple

// Disabled
v-ripple="false"

// Custom CSS class on the ripple element
v-ripple="{ class: 'my-ripple' }"

// Always emanate from element center
v-ripple.center

// Clip to a circle
v-ripple.circle

// Stop pointer-event propagation after ripple
v-ripple.stop
